-- Baza: Rus Tili — database schema for Supabase (Postgres)
-- Run this once in your Supabase project's SQL Editor (Dashboard → SQL Editor → New query)

create table if not exists lessons (
  id integer primary key,
  t text not null,
  tr text default '',
  cat text default '',
  lv text not null,
  p jsonb not null default '[]',
  sort_order integer not null default 0
);

create table if not exists users (
  id bigserial primary key,
  tg_id bigint unique not null,
  first_name text default '',
  last_name text default '',
  username text default '',
  xp integer not null default 0,
  streak integer not null default 0,
  last_day text default '',
  done jsonb not null default '[]',
  words jsonb not null default '[]',
  banned boolean not null default false,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create index if not exists idx_users_xp on users (xp desc);
create index if not exists idx_users_tg_id on users (tg_id);

-- Row Level Security: lock the tables down completely.
-- All access goes through our serverless functions using the service-role key,
-- never directly from the browser, so RLS should block anonymous/public access entirely.
alter table lessons enable row level security;
alter table users enable row level security;
-- (No policies added on purpose — default-deny. The service role key bypasses RLS.)

